import { useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { useData } from "../contexts/DataContext";
import { Button } from "../components/ui/button";
import { Input } from "../components/ui/input";
import { Checkbox } from "../components/ui/checkbox";
import { Dialog, DialogContent } from "../components/ui/dialog";
import { CheckCircle2, User } from "lucide-react";
import { toast } from "sonner";

export default function DetailVerifikasi() {
  const { id } = useParams();
  const { orders, verifyOrder } = useData();
  const navigate = useNavigate();
  const order = orders.find((o) => o.id === id);

  const [agree, setAgree] = useState(false);
  const [driver, setDriver] = useState({ name: "", plate: "" });
  const [showSuccess, setShowSuccess] = useState(false);

  if (!order) {
    return (
      <div className="max-w-[1100px]">
        <p className="text-gray-500">Pesanan tidak ditemukan.</p>
        <Button onClick={() => navigate("/pesanan")} className="mt-4">
          Kembali
        </Button>
      </div>
    );
  }

  const handleVerify = () => {
    if (!agree) return toast.error("Centang persetujuan terlebih dahulu");
    if (!driver.name || !driver.plate)
      return toast.error("Lengkapi info pengantar");
    verifyOrder(order.id, driver);
    setShowSuccess(true);
  };

  return (
    <div className="max-w-[1100px]" data-testid="detail-verifikasi-page">
      {/* Header */}
      <h1 className="text-3xl font-extrabold text-gray-900">Detail Pesanan</h1>
      <h2
        className="text-3xl font-extrabold mt-1"
        style={{ color: "#FFA000" }}
      >
        #{order.id}
      </h2>
      <div className="mt-2 text-[11px] tracking-wider uppercase text-gray-400">
        Data Pesanan{" "}
        <span className="text-gray-300 mx-1">›</span>
        <span className="font-semibold" style={{ color: "#FFA000" }}>
          Pesanan MP-{order.manifestId}
        </span>
      </div>
      <p className="text-sm text-gray-500 mt-3 mb-7">
        Periksa kelengkapan data sebelum membuat invoice
      </p>

      {/* Informasi Pelanggan + Muatan Card */}
      <div
        className="bg-white rounded-xl shadow-sm p-7 border-l-4 relative"
        style={{ borderLeftColor: "#FFA000" }}
      >
        {/* Manifest Badge */}
        <span
          className="absolute right-7 top-7 text-[10px] font-bold tracking-wider text-white px-3 py-1 rounded"
          style={{ backgroundColor: "#FFA000" }}
        >
          MANIFEST ID: #{order.manifestId}
        </span>

        {/* Informasi Pelanggan */}
        <div className="text-[11px] tracking-[0.15em] uppercase text-gray-400 font-semibold mb-5">
          Informasi Pelanggan
        </div>

        <div className="grid grid-cols-2 gap-x-16 gap-y-5">
          <Field
            label="Nama Pengirim / Gudang"
            value={order.sender.name}
            bold
          />
          <Field
            label="Nama Penerima / Gudang"
            value={order.receiver.name}
            bold
          />
          <Field label="PIC Pengirim" value={order.sender.pic} bold />
          <Field label="PIC Penerima" value={order.receiver.pic} bold />
          <Field
            label="Nomor Telepon Pengirim"
            value={order.sender.phone}
            bold
          />
          <Field
            label="Nomor Telepon Penerima"
            value={order.receiver.phone}
            bold
          />
        </div>

        {/* Divider */}
        <div className="border-t border-gray-100 mt-7 pt-6">
          <div className="text-[11px] tracking-[0.15em] uppercase text-gray-400 font-semibold mb-3">
            Informasi Muatan
          </div>
          <div className="text-2xl font-bold text-gray-900 mb-5">
            {order.cargo.title}
          </div>

          {/* Stats */}
          <div className="grid grid-cols-3 gap-4 mb-6">
            <Stat
              label="Total Berat"
              value={order.cargo.weight}
              unit="KG"
            />
            <Stat
              label="Jenis Paket"
              value={order.cargo.packageType}
              unit=""
            />
            <Stat
              label="Total Paket"
              value={order.cargo.totalPackage}
              unit="PAKET"
            />
          </div>

          {/* Vehicle */}
          <div className="flex items-center gap-4">
            <img
              src={order.vehicle.image}
              alt={order.vehicle.type}
              className="w-28 h-20 rounded-lg object-cover bg-gray-100 flex-shrink-0"
            />
            <div>
              <div className="text-lg font-bold text-gray-900">
                {order.vehicle.type}
              </div>
              <div className="text-sm text-gray-500 flex items-center gap-1 mt-1">
                <span style={{ color: "#FFA000" }}>⬡</span>
                <span>Kapasitas:{" "}</span>
                <span className="font-semibold text-gray-700">
                  {order.vehicle.capacity}
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Rute Pengiriman + Approval side by side */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mt-6">
        {/* Rute Pengiriman */}
        <div className="bg-white rounded-xl shadow-sm p-7">
          <div className="text-[11px] tracking-[0.15em] uppercase text-gray-400 font-semibold mb-5">
            Rute Pengiriman
          </div>
          <div className="space-y-6">
            <RoutePoint
              type="muat"
              city={order.route.pickup.city}
              name={order.route.pickup.name}
              address={order.route.pickup.address}
            />
            <RoutePoint
              type="bongkar"
              city={order.route.dropoff.city}
              name={order.route.dropoff.name}
              address={order.route.dropoff.address}
            />
          </div>
        </div>

        {/* Approval + Tombol */}
        <div className="bg-white rounded-xl shadow-sm p-7 flex flex-col justify-between">
          <label className="flex items-start gap-3 cursor-pointer">
            <Checkbox
              checked={agree}
              onCheckedChange={setAgree}
              data-testid="agree-checkbox"
              className="mt-0.5 flex-shrink-0"
            />
            <span className="text-sm text-gray-500 leading-relaxed">
              Saya menyatakan bahwa seluruh informasi di atas adalah benar dan
              saya menyetujui{" "}
              <span
                className="font-semibold"
                style={{ color: "#FFA000" }}
              >
                Syarat &amp; Ketentuan
              </span>{" "}
              pengiriman LogisticsLedger.
            </span>
          </label>

          <div className="flex items-center justify-end gap-4 mt-8">
            <button
              onClick={() => navigate(-1)}
              data-testid="back-btn"
              className="h-12 px-6 text-sm font-medium text-gray-700 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors"
            >
              Kembali
            </button>
            <button
              onClick={handleVerify}
              data-testid="verifikasi-pesanan-btn"
              className="h-12 px-6 text-[11px] tracking-wider text-white font-bold rounded-lg leading-tight transition-opacity hover:opacity-90"
              style={{ backgroundColor: "#FFA000" }}
            >
              VERIFIKASI
              <br />
              PESANAN
            </button>
          </div>
        </div>
      </div>

      {/* Informasi Pengantar — full width below */}
      <div className="bg-white rounded-xl shadow-sm p-7 mt-6">
        <div className="text-[11px] tracking-[0.15em] uppercase text-gray-400 font-semibold mb-5">
          Informasi Pengantar
        </div>
        <div className="flex items-start gap-5">
          {/* Avatar placeholder */}
          <div className="w-20 h-20 rounded-lg bg-gray-100 flex items-center justify-center flex-shrink-0">
            <User className="w-8 h-8 text-gray-400" />
          </div>

          {/* Inputs */}
          <div className="flex-1 space-y-3 max-w-xs">
            <div>
              <label className="text-[10px] tracking-wider uppercase text-gray-400 font-semibold">
                Nama Driver
              </label>
              <Input
                data-testid="driver-name"
                placeholder="cth: Budi"
                value={driver.name}
                onChange={(e) =>
                  setDriver({ ...driver, name: e.target.value })
                }
                className="mt-1 bg-gray-50 border-gray-100 text-sm"
              />
            </div>
            <div>
              <label className="text-[10px] tracking-wider uppercase text-gray-400 font-semibold">
                Plat Nomor
              </label>
              <Input
                data-testid="driver-plate"
                placeholder="cth: BK 4511 IA"
                value={driver.plate}
                onChange={(e) =>
                  setDriver({ ...driver, plate: e.target.value })
                }
                className="mt-1 bg-gray-50 border-gray-100 text-sm"
              />
            </div>
          </div>
        </div>
      </div>

      {/* Success Modal */}
      <Dialog open={showSuccess} onOpenChange={setShowSuccess}>
        <DialogContent
          className="max-w-md text-center py-12"
          data-testid="verify-success-modal"
        >
          <div className="flex flex-col items-center gap-5">
            <div className="w-20 h-20 rounded-full bg-emerald-50 flex items-center justify-center">
              <CheckCircle2 className="w-12 h-12 text-emerald-500" />
            </div>
            <div>
              <div className="text-lg font-bold tracking-wider text-gray-900">
                VERIFIKASI PESANAN BERHASIL
              </div>
              <div className="text-xs text-gray-500 mt-2 tracking-wider uppercase">
                Silahkan melihat riwayat di status pengiriman
              </div>
            </div>
            <button
              onClick={() => navigate("/status-pengiriman")}
              className="mt-2 h-10 px-8 text-white text-sm font-semibold rounded-lg transition-opacity hover:opacity-90"
              style={{ backgroundColor: "#FFA000" }}
              data-testid="goto-status-btn"
            >
              Lihat Status
            </button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

/* ─── Sub-components ─────────────────────────────────────────────────────── */

function Field({ label, value, bold }) {
  return (
    <div>
      <div className="text-[10px] tracking-[0.15em] uppercase text-gray-400 font-semibold">
        {label}
      </div>
      <div
        className={`mt-1 text-gray-900 ${
          bold ? "font-bold text-[15px]" : "text-sm"
        }`}
      >
        {value}
      </div>
    </div>
  );
}

function Stat({ label, value, unit }) {
  return (
    <div className="bg-gray-50 rounded-xl p-4">
      <div className="text-[10px] tracking-[0.15em] uppercase text-gray-400 font-semibold">
        {label}
      </div>
      <div className="mt-2 text-gray-900 flex items-baseline gap-1">
        <span className="text-xl font-bold">{value}</span>
        {unit && <span className="text-xs text-gray-400">{unit}</span>}
      </div>
    </div>
  );
}

function RoutePoint({ type, city, name, address }) {
  const isMuat = type === "muat";
  return (
    <div className="flex gap-3">
      {/* Timeline indicator */}
      <div className="flex flex-col items-center pt-1">
        <div
          className="w-3.5 h-3.5 rounded-full border-[3px] bg-white flex-shrink-0"
          style={{ borderColor: "#FFA000" }}
        />
        {isMuat && (
          <div className="w-px flex-1 border-l-2 border-dashed border-gray-200 mt-1" />
        )}
      </div>

      {/* Content */}
      <div className="flex-1 pb-1">
        <div
          className="text-[10px] tracking-[0.15em] uppercase font-bold"
          style={{ color: "#FFA000" }}
        >
          Titik {isMuat ? "Muat" : "Bongkar"} — {city}
        </div>
        <div className="text-[15px] font-bold text-gray-900 mt-1">{name}</div>
        <div className="text-xs text-gray-500 mt-0.5">{address}</div>
      </div>
    </div>
  );
}
